using System;
using System.Linq;
using System.Collections.Generic;

class Program
{
    static void Main()
    {
        string text = "Merhaba dunya bu bir test metni. Bu metin kelime sayma icin kullanilacak. Merhaba tekrar!";

        // Kelimelere ayir
        string[] words = text.Split(new char[] { ' ', '.', ',', '!' }, StringSplitOptions.RemoveEmptyEntries);

        Console.WriteLine("Toplam kelime sayisi: " + words.Length);
        Console.WriteLine("Toplam karakter sayisi: " + text.Length);

        // Kelime frekansi
        Dictionary<string, int> wordCount = new Dictionary<string, int>();

        foreach (string word in words)
        {
            string lowerWord = word.ToLower();
            if (wordCount.ContainsKey(lowerWord))
            {
                wordCount[lowerWord]++;
            }
            else
            {
                wordCount[lowerWord] = 1;
            }
        }

        Console.WriteLine("\nKelime frekanslari:");
        foreach (var pair in wordCount.OrderByDescending(p => p.Value))
        {
            Console.WriteLine($"'{pair.Key}': {pair.Value} kez");
        }

        // En uzun kelime
        string longestWord = words.OrderByDescending(w => w.Length).First();
        Console.WriteLine($"\nEn uzun kelime: '{longestWord}' ({longestWord.Length} karakter)");

        // Ortalama kelime uzunlugu
        double avgLength = words.Average(w => w.Length);
        Console.WriteLine($"Ortalama kelime uzunlugu: {avgLength:F2}");
    }
}
